import sqlite3
import re
from flask import Flask, render_template, request, session, redirect, url_for
from config import Config

app = Flask(__name__)
app.config.from_object(Config)

def get_db_connection():
    conn = sqlite3.connect('/tmp/velopath.db')
    conn.row_factory = sqlite3.Row
    return conn

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        # Secure login implementation
        conn = get_db_connection()
        user = conn.execute('SELECT * FROM users WHERE username = ? AND password = ?', (username, password)).fetchone()
        conn.close()
        if user:
            session['user'] = user['username']
            return redirect(url_for('dashboard'))
        return render_template('login.html', error="Invalid credentials")
    return render_template('login.html')

@app.route('/dashboard')
def dashboard():
    if 'user' not in session:
        return redirect(url_for('login'))
    return render_template('dashboard.html', username=session['user'])

@app.route('/drivers/search')
def search_drivers():
    if 'user' not in session:
        return redirect(url_for('login'))

    query = request.args.get('q', '')
    conn = get_db_connection()
    # Red Herring: This endpoint is properly parameterized
    drivers = conn.execute("SELECT id, name, license_plate, status FROM drivers WHERE name LIKE ?", (f'%{query}%',)).fetchall()
    conn.close()
    return render_template('drivers.html', drivers=drivers, query=query)

@app.route('/inventory/search')
def search_inventory():
    if 'user' not in session:
        return redirect(url_for('login'))

    query = request.args.get('q', '')

    # Basic Security Filter - Bypassed with comments or specific whitespace
    if re.search(r"UNION\s+SELECT", query, re.IGNORECASE):
        return render_template('inventory.html', error="Security Filter Triggered: Malicious pattern detected.")

    conn = get_db_connection()
    try:
        # Vulnerable Injection Point
        sql = f"SELECT id, item_name, sku, quantity, warehouse_loc FROM inventory WHERE item_name LIKE '%{query}%'"
        items = conn.execute(sql).fetchall()
        return render_template('inventory.html', items=items, query=query)
    except Exception as e:
        return render_template('inventory.html', error="A database error occurred during your search.")
    finally:
        conn.close()

@app.route('/logout')
def logout():
    session.pop('user', None)
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)

